package be.schaubroeck.lpb.rkm.rekenmotor.service;

import be.schaubroeck.lpb.rkm.rekenmotor.PlanningsurenCoreHrConfiguratie;
import be.schaubroeck.lpb.tools.AardKodeExtensie;
import be.schaubroeck.lpb.tools.api.dto.AardKodeExtensieDTO;
import be.schaubroeck.lpb.tools.corehr.extern.uitgaand.rekenmotor.rekenmotor.PlanningsurenConfigDTO;
import be.schaubroeck.temporal.util.TimeToolkit;
import org.joda.time.LocalDate;
import org.springframework.context.annotation.Lazy;
import org.springframework.stereotype.Service;

import java.util.Collections;
import java.util.List;

import static java.util.stream.Collectors.toList;

@Lazy
@Service
public class RkmPlanningsurenConfiguratieMapper {

    public static final LocalDate END_DATE_IF_NULL = TimeToolkit.endOfTime().toLocalDate();

    public List<PlanningsurenCoreHrConfiguratie> map(List<PlanningsurenConfigDTO> planningsurenConfigList) {
        if (planningsurenConfigList == null || planningsurenConfigList.isEmpty()) {
            return Collections.emptyList();
        }
        return planningsurenConfigList.stream()
                .map(config -> PlanningsurenCoreHrConfiguratie.builder()
                        .actualFrom(config.getActualFrom())
                        .actualTo(config.getActualTo() != null ? config.getActualTo() : END_DATE_IF_NULL)
                        .werkgeverId(config.getWerkgeverId())
                        .planningsuren(config.isPlanningsuren())
                        .langdurigeAkes(toAkes(config.getLangdurigeAkes()))
                        .uitzonderlijkePlanningsuren(config.isUitzonderlijkePlanningsuren())
                        .uitzonderlijkeAkes(toAkes(config.getUitzonderlijkeAkes()))
                        .build())
                .collect(toList());
    }

    private List<AardKodeExtensie> toAkes(List<AardKodeExtensieDTO> akeDtos) {
        if (akeDtos == null || akeDtos.isEmpty()) {
            return Collections.emptyList();
        } else {
            return akeDtos
                    .stream()
                    .map(dto -> {
                        AardKodeExtensie ake = dto.getAardKodeExtensie();
                        ake.setAard(dto.getAard());
                        ake.setCode(dto.getCode());
                        ake.setExtensie(dto.getExtensie());
                        return ake;
                    }).collect(toList());
        }
    }
}
